"use client";

import { ChangeEvent, FormEvent, useCallback, useEffect, useMemo, useState } from "react";
import { upload } from "@imagekit/next";
import {
  AMENITY_OPTIONS,
  AREA_UNITS,
  FACING_OPTIONS,
  LISTING_TYPES,
  PRICE_UNITS,
  PROJECT_STATUSES,
  PROPERTY_RECORD_STATUSES,
  PROPERTY_TYPES,
  type UserRole,
} from "@/lib/constants";

type SessionUser = {
  id: string;
  name: string;
  email: string;
  role: UserRole;
};

type SetupStatus = {
  adminExists: boolean;
  managerCount: number;
};

type UserProfile = {
  _id: string;
  name: string;
  email: string;
  role: UserRole;
};

type PropertyItem = {
  _id: string;
  propertyTitle: string;
  propertyType: string;
  listingType: string;
  price: number;
  priceUnit: string;
  areaSize: number;
  areaUnit: string;
  propertyCode: string;
  city: string;
  areaSector: string;
  fullAddress: string;
  mapLocation: { lat: number; lng: number };
  builderName: string;
  projectName: string;
  projectStatus: string;
  possessionDate?: string | null;
  reraNumber?: string;
  flatConfig: {
    bhk?: number | null;
    bathrooms?: number | null;
    balconies?: number | null;
    floorNumber?: number | null;
    totalFloors?: number | null;
  };
  plotConfig: {
    plotArea?: number | null;
    facing?: string | null;
    roadWidth?: number | null;
  };
  coverImageUrl: string;
  galleryImageUrls: string[];
  videoUrl?: string;
  view360Url?: string;
  shortDescription: string;
  detailedDescription: string;
  keyHighlights: string[];
  amenities: string[];
  contactName: string;
  phoneNumber: string;
  whatsappNumber: string;
  alternateNumber?: string;
  featuredProperty: boolean;
  verifiedBadge: boolean;
  newLaunch: boolean;
  recordStatus: string;
  metaTitle: string;
  metaDescription: string;
  slug: string;
};

type PropertyForm = {
  propertyTitle: string;
  propertyType: string;
  listingType: string;
  price: string;
  priceUnit: string;
  areaSize: string;
  areaUnit: string;
  propertyCode: string;
  city: string;
  areaSector: string;
  fullAddress: string;
  lat: string;
  lng: string;
  builderName: string;
  projectName: string;
  projectStatus: string;
  possessionDate: string;
  reraNumber: string;
  bhk: string;
  bathrooms: string;
  balconies: string;
  floorNumber: string;
  totalFloors: string;
  plotArea: string;
  facing: string;
  roadWidth: string;
  coverImageUrl: string;
  galleryImageUrls: string[];
  videoUrl: string;
  view360Url: string;
  shortDescription: string;
  detailedDescription: string;
  keyHighlightsText: string;
  amenities: string[];
  contactName: string;
  phoneNumber: string;
  whatsappNumber: string;
  alternateNumber: string;
  featuredProperty: boolean;
  verifiedBadge: boolean;
  newLaunch: boolean;
  recordStatus: string;
  metaTitle: string;
  metaDescription: string;
  slug: string;
};

const initialPropertyForm: PropertyForm = {
  propertyTitle: "",
  propertyType: "plot",
  listingType: "sale",
  price: "",
  priceUnit: "total",
  areaSize: "",
  areaUnit: "sqyd",
  propertyCode: "",
  city: "Kurukshetra",
  areaSector: "",
  fullAddress: "",
  lat: "",
  lng: "",
  builderName: "",
  projectName: "",
  projectStatus: "ready_to_move",
  possessionDate: "",
  reraNumber: "",
  bhk: "",
  bathrooms: "",
  balconies: "",
  floorNumber: "",
  totalFloors: "",
  plotArea: "",
  facing: "",
  roadWidth: "",
  coverImageUrl: "",
  galleryImageUrls: [],
  videoUrl: "",
  view360Url: "",
  shortDescription: "",
  detailedDescription: "",
  keyHighlightsText: "",
  amenities: [],
  contactName: "",
  phoneNumber: "",
  whatsappNumber: "",
  alternateNumber: "",
  featuredProperty: false,
  verifiedBadge: false,
  newLaunch: false,
  recordStatus: "draft",
  metaTitle: "",
  metaDescription: "",
  slug: "",
};

function parseLines(value: string) {
  return value
    .split("\n")
    .map((entry) => entry.trim())
    .filter((entry) => entry.length > 0);
}

const MAX_IMAGE_UPLOAD_BYTES = 500 * 1024;

const propertyWizardSteps = [
  "Basics",
  "Location",
  "Media",
  "Content",
  "SEO & Publish",
] as const;

type CmsView = "banner" | "managers" | "propertyWizard" | "records";

export default function CmsApp() {
  const [setup, setSetup] = useState<SetupStatus | null>(null);
  const [user, setUser] = useState<SessionUser | null>(null);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [properties, setProperties] = useState<PropertyItem[]>([]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");
  const [submittingProperty, setSubmittingProperty] = useState(false);
  const [uploadingCover, setUploadingCover] = useState(false);
  const [uploadingGallery, setUploadingGallery] = useState(false);
  const [uploadingBannerImage, setUploadingBannerImage] = useState(false);
  const [activeView, setActiveView] = useState<CmsView>("propertyWizard");
  const [propertyStep, setPropertyStep] = useState(0);

  const [loginForm, setLoginForm] = useState({ email: "", password: "" });
  const [bootstrapForm, setBootstrapForm] = useState({
    name: "",
    email: "",
    password: "",
  });
  const [managerForm, setManagerForm] = useState({
    name: "",
    email: "",
    password: "",
  });
  const [bannerForm, setBannerForm] = useState({
    projectName: "Rite Realty",
    title: "",
    subtitle: "",
    imageUrl: "",
    ctaLabel: "Explore Projects",
    ctaHref: "/projects/new-launch",
  });
  const [propertyForm, setPropertyForm] = useState<PropertyForm>(initialPropertyForm);

  const isAdmin = user?.role === "admin";

  const canDeleteProperty = useMemo(() => isAdmin, [isAdmin]);

  const initialize = useCallback(async () => {
    setLoading(true);
    const [setupRes, meRes] = await Promise.all([
      fetch("/api/auth/setup-status", { cache: "no-store" }),
      fetch("/api/auth/me", { cache: "no-store" }),
    ]);
    const setupData = (await setupRes.json()) as SetupStatus;
    const meData = (await meRes.json()) as { user: SessionUser | null };
    setSetup(setupData);
    setUser(meData.user);
    setLoading(false);
  }, []);

  const loadProperties = useCallback(async () => {
    const response = await fetch("/api/properties?all=1", { cache: "no-store" });
    const data = (await response.json()) as { properties?: PropertyItem[]; error?: string };
    if (!response.ok) {
      setMessage(data.error ?? "Unable to load properties.");
      return;
    }
    setProperties(data.properties ?? []);
  }, []);

  const loadUsers = useCallback(async () => {
    if (!isAdmin) {
      return;
    }
    const response = await fetch("/api/users", { cache: "no-store" });
    if (!response.ok) {
      return;
    }
    const data = (await response.json()) as { users: UserProfile[] };
    setUsers(data.users);
  }, [isAdmin]);

  useEffect(() => {
    void initialize();
  }, [initialize]);

  useEffect(() => {
    if (!user) {
      return;
    }
    void loadProperties();
    void loadUsers();
  }, [user, isAdmin, loadProperties, loadUsers]);

  function ensureValidImage(file: File, label: string) {
    if (!file.type.startsWith("image/")) {
      throw new Error(`${label} must be an image file.`);
    }
    if (file.size > MAX_IMAGE_UPLOAD_BYTES) {
      throw new Error(`${label} must be 500KB or smaller.`);
    }
  }

  async function uploadSingleFile(file: File, folder: string) {
    const authRes = await fetch("/api/imagekit/auth", { cache: "no-store" });
    const authData = (await authRes.json()) as {
      token: string;
      expire: number;
      signature: string;
      publicKey: string;
      error?: string;
    };

    if (!authRes.ok) {
      throw new Error(authData.error ?? "ImageKit auth failed.");
    }

    const result = await upload({
      file,
      fileName: file.name,
      token: authData.token,
      expire: authData.expire,
      signature: authData.signature,
      publicKey: authData.publicKey,
      folder,
      useUniqueFileName: true,
    });

    if (!result.url) {
      throw new Error("Upload succeeded but URL was not returned by ImageKit.");
    }

    return result.url;
  }

  async function handleCoverUpload(event: ChangeEvent<HTMLInputElement>) {
    const input = event.currentTarget;
    const file = input.files?.[0];
    if (!file) {
      return;
    }

    setUploadingCover(true);
    setMessage("");
    try {
      const url = await uploadSingleFile(file, "/riterealty/properties/cover");
      setPropertyForm((prev) => ({ ...prev, coverImageUrl: url }));
      setMessage("Cover image uploaded.");
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Cover upload failed.");
    } finally {
      input.value = "";
      setUploadingCover(false);
    }
  }

  async function handleGalleryUpload(event: ChangeEvent<HTMLInputElement>) {
    const input = event.currentTarget;
    const files = Array.from(input.files ?? []);
    if (files.length === 0) {
      return;
    }

    setUploadingGallery(true);
    setMessage("");
    try {
      const uploaded = await Promise.all(
        files.map((file) => uploadSingleFile(file, "/riterealty/properties/gallery"))
      );
      setPropertyForm((prev) => ({
        ...prev,
        galleryImageUrls: [...prev.galleryImageUrls, ...uploaded],
      }));
      setMessage("Gallery images uploaded.");
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Gallery upload failed.");
    } finally {
      input.value = "";
      setUploadingGallery(false);
    }
  }

  async function handleLogin(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setMessage("");
    const response = await fetch("/api/auth/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(loginForm),
    });
    const data = (await response.json()) as { user?: SessionUser; error?: string };
    if (!response.ok || !data.user) {
      setMessage(data.error ?? "Login failed.");
      return;
    }
    setUser(data.user);
    setLoginForm({ email: "", password: "" });
    setMessage("Logged in.");
  }

  async function handleBootstrapAdmin(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setMessage("");
    const response = await fetch("/api/auth/bootstrap-admin", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(bootstrapForm),
    });
    const data = (await response.json()) as { user?: SessionUser; error?: string };
    if (!response.ok || !data.user) {
      setMessage(data.error ?? "Could not create admin.");
      return;
    }
    setUser(data.user);
    setBootstrapForm({ name: "", email: "", password: "" });
    setMessage("Admin account created.");
    await initialize();
  }

  async function handleLogout() {
    await fetch("/api/auth/logout", { method: "POST" });
    setUser(null);
    setUsers([]);
    setProperties([]);
    setEditingId(null);
    setPropertyForm(initialPropertyForm);
    setMessage("Logged out.");
    await initialize();
  }

  async function handleBannerSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setMessage("");
    const response = await fetch("/api/banner", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(bannerForm),
    });
    const data = (await response.json()) as { error?: string };
    if (!response.ok) {
      setMessage(data.error ?? "Banner update failed.");
      return;
    }
    setMessage("Banner updated.");
  }

  async function handleManagerCreate(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setMessage("");
    const response = await fetch("/api/users", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ ...managerForm, role: "manager" }),
    });
    const data = (await response.json()) as { error?: string };
    if (!response.ok) {
      setMessage(data.error ?? "Could not create manager.");
      return;
    }
    setManagerForm({ name: "", email: "", password: "" });
    setMessage("Manager account created.");
    await initialize();
    await loadUsers();
  }

  async function handlePropertySubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setSubmittingProperty(true);
    setMessage("");

    const payload = {
      propertyTitle: propertyForm.propertyTitle,
      propertyType: propertyForm.propertyType,
      listingType: propertyForm.listingType,
      price: propertyForm.price,
      priceUnit: propertyForm.priceUnit,
      areaSize: propertyForm.areaSize,
      areaUnit: propertyForm.areaUnit,
      propertyCode: propertyForm.propertyCode,
      city: propertyForm.city,
      areaSector: propertyForm.areaSector,
      fullAddress: propertyForm.fullAddress,
      mapLocation: { lat: propertyForm.lat, lng: propertyForm.lng },
      builderName: propertyForm.builderName,
      projectName: propertyForm.projectName,
      projectStatus: propertyForm.projectStatus,
      possessionDate: propertyForm.possessionDate || null,
      reraNumber: propertyForm.reraNumber,
      flatConfig: {
        bhk: propertyForm.bhk,
        bathrooms: propertyForm.bathrooms,
        balconies: propertyForm.balconies,
        floorNumber: propertyForm.floorNumber,
        totalFloors: propertyForm.totalFloors,
      },
      plotConfig: {
        plotArea: propertyForm.plotArea,
        facing: propertyForm.facing || null,
        roadWidth: propertyForm.roadWidth,
      },
      coverImageUrl: propertyForm.coverImageUrl,
      galleryImageUrls: propertyForm.galleryImageUrls,
      videoUrl: propertyForm.videoUrl,
      view360Url: propertyForm.view360Url,
      shortDescription: propertyForm.shortDescription,
      detailedDescription: propertyForm.detailedDescription,
      keyHighlights: parseLines(propertyForm.keyHighlightsText),
      amenities: propertyForm.amenities,
      contactName: propertyForm.contactName,
      phoneNumber: propertyForm.phoneNumber,
      whatsappNumber: propertyForm.whatsappNumber,
      alternateNumber: propertyForm.alternateNumber,
      featuredProperty: propertyForm.featuredProperty,
      verifiedBadge: propertyForm.verifiedBadge,
      newLaunch: propertyForm.newLaunch,
      recordStatus: propertyForm.recordStatus,
      metaTitle: propertyForm.metaTitle,
      metaDescription: propertyForm.metaDescription,
      slug: propertyForm.slug || undefined,
    };

    const endpoint = editingId ? `/api/properties/${editingId}` : "/api/properties";
    const method = editingId ? "PUT" : "POST";

    const response = await fetch(endpoint, {
      method,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const data = (await response.json()) as { error?: string };
    if (!response.ok) {
      setMessage(data.error ?? "Property save failed.");
      setSubmittingProperty(false);
      return;
    }

    setMessage(editingId ? "Property updated." : "Property created.");
    setPropertyForm(initialPropertyForm);
    setEditingId(null);
    setSubmittingProperty(false);
    await loadProperties();
  }

  function startEdit(property: PropertyItem) {
    setEditingId(property._id);
    setPropertyForm({
      propertyTitle: property.propertyTitle,
      propertyType: property.propertyType,
      listingType: property.listingType,
      price: String(property.price),
      priceUnit: property.priceUnit,
      areaSize: String(property.areaSize),
      areaUnit: property.areaUnit,
      propertyCode: property.propertyCode,
      city: property.city,
      areaSector: property.areaSector,
      fullAddress: property.fullAddress,
      lat: String(property.mapLocation.lat),
      lng: String(property.mapLocation.lng),
      builderName: property.builderName,
      projectName: property.projectName,
      projectStatus: property.projectStatus,
      possessionDate: property.possessionDate
        ? new Date(property.possessionDate).toISOString().slice(0, 10)
        : "",
      reraNumber: property.reraNumber ?? "",
      bhk: property.flatConfig.bhk ? String(property.flatConfig.bhk) : "",
      bathrooms: property.flatConfig.bathrooms ? String(property.flatConfig.bathrooms) : "",
      balconies: property.flatConfig.balconies ? String(property.flatConfig.balconies) : "",
      floorNumber: property.flatConfig.floorNumber ? String(property.flatConfig.floorNumber) : "",
      totalFloors: property.flatConfig.totalFloors ? String(property.flatConfig.totalFloors) : "",
      plotArea: property.plotConfig.plotArea ? String(property.plotConfig.plotArea) : "",
      facing: property.plotConfig.facing ?? "",
      roadWidth: property.plotConfig.roadWidth ? String(property.plotConfig.roadWidth) : "",
      coverImageUrl: property.coverImageUrl,
      galleryImageUrls: property.galleryImageUrls ?? [],
      videoUrl: property.videoUrl ?? "",
      view360Url: property.view360Url ?? "",
      shortDescription: property.shortDescription,
      detailedDescription: property.detailedDescription,
      keyHighlightsText: property.keyHighlights.join("\n"),
      amenities: property.amenities,
      contactName: property.contactName,
      phoneNumber: property.phoneNumber,
      whatsappNumber: property.whatsappNumber,
      alternateNumber: property.alternateNumber ?? "",
      featuredProperty: property.featuredProperty,
      verifiedBadge: property.verifiedBadge,
      newLaunch: property.newLaunch,
      recordStatus: property.recordStatus,
      metaTitle: property.metaTitle,
      metaDescription: property.metaDescription,
      slug: property.slug,
    });
    window.scrollTo({ top: 0, behavior: "smooth" });
  }

  async function deleteProperty(id: string) {
    if (!canDeleteProperty) {
      return;
    }
    if (!window.confirm("Delete this property?")) {
      return;
    }

    const response = await fetch(`/api/properties/${id}`, { method: "DELETE" });
    const data = (await response.json()) as { error?: string };
    if (!response.ok) {
      setMessage(data.error ?? "Delete failed.");
      return;
    }
    setMessage("Property deleted.");
    await loadProperties();
  }

  if (loading) {
    return <p className="text-sm text-zinc-600">Loading CMS...</p>;
  }

  if (!user) {
    return (
      <section className="mx-auto max-w-md rounded-2xl border border-zinc-200 bg-white p-6 shadow-sm">
        <h1 className="text-2xl font-semibold text-zinc-900">Rite Realty CMS</h1>
        <p className="mt-2 text-sm text-zinc-600">
          {setup?.adminExists
            ? "Login as admin or manager."
            : "No admin found. Create the first admin account."}
        </p>

        {!setup?.adminExists ? (
          <form onSubmit={handleBootstrapAdmin} className="mt-5 grid gap-3">
            <input
              required
              value={bootstrapForm.name}
              onChange={(event) =>
                setBootstrapForm((prev) => ({ ...prev, name: event.target.value }))
              }
              placeholder="Admin Name"
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            />
            <input
              required
              type="email"
              value={bootstrapForm.email}
              onChange={(event) =>
                setBootstrapForm((prev) => ({ ...prev, email: event.target.value }))
              }
              placeholder="Admin Email"
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            />
            <input
              required
              type="password"
              value={bootstrapForm.password}
              onChange={(event) =>
                setBootstrapForm((prev) => ({ ...prev, password: event.target.value }))
              }
              placeholder="Password (min 8)"
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            />
            <button className="rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white">
              Create Admin
            </button>
          </form>
        ) : (
          <form onSubmit={handleLogin} className="mt-5 grid gap-3">
            <input
              required
              type="email"
              value={loginForm.email}
              onChange={(event) =>
                setLoginForm((prev) => ({ ...prev, email: event.target.value }))
              }
              placeholder="Email"
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            />
            <input
              required
              type="password"
              value={loginForm.password}
              onChange={(event) =>
                setLoginForm((prev) => ({ ...prev, password: event.target.value }))
              }
              placeholder="Password"
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            />
            <button className="rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white">
              Login
            </button>
          </form>
        )}

        {message ? <p className="mt-3 text-sm text-zinc-700">{message}</p> : null}
      </section>
    );
  }

  return (
    <section className="space-y-6">
      <div className="rounded-2xl border border-zinc-200 bg-white p-5 shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div>
            <h1 className="text-2xl font-semibold text-zinc-900">Rite Realty CMS</h1>
            <p className="text-sm text-zinc-600">
              Logged in as {user.name} ({user.role})
            </p>
          </div>
          <button
            onClick={handleLogout}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm font-semibold text-zinc-700"
          >
            Logout
          </button>
        </div>
        {message ? <p className="mt-3 text-sm text-zinc-700">{message}</p> : null}
      </div>

      <div className="rounded-2xl border border-zinc-200 bg-white p-5 shadow-sm">
        <h2 className="text-xl font-semibold text-zinc-900">Latest Project Banner</h2>
        <form onSubmit={handleBannerSubmit} className="mt-4 grid gap-3 md:grid-cols-2">
          <input
            required
            value={bannerForm.projectName}
            onChange={(event) =>
              setBannerForm((prev) => ({ ...prev, projectName: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Project name"
          />
          <input
            required
            value={bannerForm.title}
            onChange={(event) => setBannerForm((prev) => ({ ...prev, title: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Banner title"
          />
          <input
            required
            value={bannerForm.subtitle}
            onChange={(event) =>
              setBannerForm((prev) => ({ ...prev, subtitle: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            placeholder="Subtitle"
          />
          <input
            required
            value={bannerForm.imageUrl}
            onChange={(event) =>
              setBannerForm((prev) => ({ ...prev, imageUrl: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            placeholder="Image URL"
          />
          <input
            required
            value={bannerForm.ctaLabel}
            onChange={(event) =>
              setBannerForm((prev) => ({ ...prev, ctaLabel: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="CTA label"
          />
          <input
            required
            value={bannerForm.ctaHref}
            onChange={(event) =>
              setBannerForm((prev) => ({ ...prev, ctaHref: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="CTA href"
          />
          <button className="rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white md:col-span-2">
            Update Banner
          </button>
        </form>
      </div>

      {isAdmin ? (
        <div className="rounded-2xl border border-zinc-200 bg-white p-5 shadow-sm">
          <h2 className="text-xl font-semibold text-zinc-900">Manager Accounts</h2>
          <p className="mt-1 text-sm text-zinc-600">
            Limit: 2 managers. Current: {setup?.managerCount ?? 0}
          </p>
          <form onSubmit={handleManagerCreate} className="mt-4 grid gap-3 md:grid-cols-3">
            <input
              required
              value={managerForm.name}
              onChange={(event) =>
                setManagerForm((prev) => ({ ...prev, name: event.target.value }))
              }
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
              placeholder="Manager name"
            />
            <input
              required
              type="email"
              value={managerForm.email}
              onChange={(event) =>
                setManagerForm((prev) => ({ ...prev, email: event.target.value }))
              }
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
              placeholder="Manager email"
            />
            <input
              required
              type="password"
              value={managerForm.password}
              onChange={(event) =>
                setManagerForm((prev) => ({ ...prev, password: event.target.value }))
              }
              className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
              placeholder="Password"
            />
            <button className="rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white md:col-span-3">
              Create Manager
            </button>
          </form>

          {users.length > 0 ? (
            <div className="mt-4 grid gap-2">
              {users.map((profile) => (
                <div key={profile._id} className="rounded-lg border border-zinc-200 px-3 py-2 text-sm">
                  {profile.name} - {profile.email} - {profile.role}
                </div>
              ))}
            </div>
          ) : null}
        </div>
      ) : null}

      <div className="rounded-2xl border border-zinc-200 bg-white p-5 shadow-sm">
        <h2 className="text-xl font-semibold text-zinc-900">
          {editingId ? "Edit Property" : "Add Property"}
        </h2>
        <p className="mt-1 text-sm text-zinc-600">
          Full property CMS form with SEO, media, amenities, lead and status controls.
        </p>

        <form onSubmit={handlePropertySubmit} className="mt-4 grid gap-3 md:grid-cols-2">
          <input
            required
            value={propertyForm.propertyTitle}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, propertyTitle: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Property Title (SEO optimized)"
          />
          <input
            value={propertyForm.slug}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, slug: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Slug (optional)"
          />
          <select
            value={propertyForm.propertyType}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, propertyType: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            {PROPERTY_TYPES.map((type) => (
              <option key={type} value={type}>
                {type}
              </option>
            ))}
          </select>
          <select
            value={propertyForm.listingType}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, listingType: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            {LISTING_TYPES.map((type) => (
              <option key={type} value={type}>
                {type}
              </option>
            ))}
          </select>
          <input
            required
            value={propertyForm.price}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, price: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Price"
          />
          <select
            value={propertyForm.priceUnit}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, priceUnit: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            {PRICE_UNITS.map((unit) => (
              <option key={unit} value={unit}>
                {unit}
              </option>
            ))}
          </select>
          <input
            required
            value={propertyForm.areaSize}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, areaSize: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Area Size"
          />
          <select
            value={propertyForm.areaUnit}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, areaUnit: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            {AREA_UNITS.map((unit) => (
              <option key={unit} value={unit}>
                {unit}
              </option>
            ))}
          </select>
          <input
            value={propertyForm.propertyCode}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, propertyCode: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Property ID (optional, auto-generated if empty)"
          />
          <input
            required
            value={propertyForm.city}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, city: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="City"
          />
          <input
            required
            value={propertyForm.areaSector}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, areaSector: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Area / Sector"
          />
          <input
            required
            value={propertyForm.fullAddress}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, fullAddress: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Full Address"
          />
          <input
            required
            value={propertyForm.lat}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, lat: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Latitude"
          />
          <input
            required
            value={propertyForm.lng}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, lng: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Longitude"
          />
          <input
            required
            value={propertyForm.builderName}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, builderName: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Builder Name"
          />
          <input
            required
            value={propertyForm.projectName}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, projectName: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Project Name"
          />
          <select
            value={propertyForm.projectStatus}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, projectStatus: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            {PROJECT_STATUSES.map((status) => (
              <option key={status} value={status}>
                {status}
              </option>
            ))}
          </select>
          <input
            type="date"
            value={propertyForm.possessionDate}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, possessionDate: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Possession Date"
          />
          <input
            value={propertyForm.reraNumber}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, reraNumber: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            placeholder="RERA Number (optional)"
          />

          <input
            value={propertyForm.bhk}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, bhk: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="BHK (for flats)"
          />
          <input
            value={propertyForm.bathrooms}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, bathrooms: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Bathrooms"
          />
          <input
            value={propertyForm.balconies}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, balconies: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Balconies"
          />
          <input
            value={propertyForm.floorNumber}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, floorNumber: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Floor Number"
          />
          <input
            value={propertyForm.totalFloors}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, totalFloors: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Total Floors"
          />
          <input
            value={propertyForm.plotArea}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, plotArea: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Plot Area (for plots)"
          />
          <select
            value={propertyForm.facing}
            onChange={(event) => setPropertyForm((prev) => ({ ...prev, facing: event.target.value }))}
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            <option value="">Facing</option>
            {FACING_OPTIONS.map((facing) => (
              <option key={facing} value={facing}>
                {facing}
              </option>
            ))}
          </select>
          <input
            value={propertyForm.roadWidth}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, roadWidth: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Road Width"
          />

          <input
            required
            value={propertyForm.coverImageUrl}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, coverImageUrl: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            placeholder="Cover Image URL"
          />
          <label className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2">
            Upload Cover Image
            <input type="file" accept="image/*" onChange={handleCoverUpload} className="mt-2 block w-full text-sm" />
            {uploadingCover ? <span className="mt-1 block text-xs">Uploading...</span> : null}
          </label>
          <label className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2">
            Upload Gallery Images
            <input
              type="file"
              accept="image/*"
              multiple
              onChange={handleGalleryUpload}
              className="mt-2 block w-full text-sm"
            />
            {uploadingGallery ? <span className="mt-1 block text-xs">Uploading...</span> : null}
          </label>
          <div className="rounded-lg border border-zinc-200 bg-zinc-50 p-3 text-xs text-zinc-700 md:col-span-2">
            Gallery URLs: {propertyForm.galleryImageUrls.join(", ") || "none"}
          </div>

          <input
            value={propertyForm.videoUrl}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, videoUrl: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Video URL (optional)"
          />
          <input
            value={propertyForm.view360Url}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, view360Url: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="360 View URL (optional)"
          />

          <textarea
            required
            value={propertyForm.shortDescription}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, shortDescription: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            rows={2}
            placeholder="Short Description"
          />
          <textarea
            required
            value={propertyForm.detailedDescription}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, detailedDescription: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            rows={4}
            placeholder="Detailed Description"
          />
          <textarea
            value={propertyForm.keyHighlightsText}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, keyHighlightsText: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            rows={3}
            placeholder="Key Highlights (one per line)"
          />

          <div className="rounded-lg border border-zinc-300 p-3 md:col-span-2">
            <p className="mb-2 text-sm font-medium text-zinc-900">Amenities</p>
            <div className="grid gap-2 md:grid-cols-3">
              {AMENITY_OPTIONS.map((amenity) => (
                <label key={amenity} className="flex items-center gap-2 text-sm text-zinc-700">
                  <input
                    type="checkbox"
                    checked={propertyForm.amenities.includes(amenity)}
                    onChange={(event) =>
                      setPropertyForm((prev) => ({
                        ...prev,
                        amenities: event.target.checked
                          ? [...prev.amenities, amenity]
                          : prev.amenities.filter((item) => item !== amenity),
                      }))
                    }
                  />
                  {amenity}
                </label>
              ))}
            </div>
          </div>

          <input
            required
            value={propertyForm.contactName}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, contactName: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Contact Name"
          />
          <input
            required
            value={propertyForm.phoneNumber}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, phoneNumber: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Phone Number"
          />
          <input
            required
            value={propertyForm.whatsappNumber}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, whatsappNumber: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="WhatsApp Number"
          />
          <input
            value={propertyForm.alternateNumber}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, alternateNumber: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Alternate Number"
          />

          <label className="flex items-center gap-2 text-sm text-zinc-700">
            <input
              type="checkbox"
              checked={propertyForm.featuredProperty}
              onChange={(event) =>
                setPropertyForm((prev) => ({ ...prev, featuredProperty: event.target.checked }))
              }
            />
            Featured Property
          </label>
          <label className="flex items-center gap-2 text-sm text-zinc-700">
            <input
              type="checkbox"
              checked={propertyForm.verifiedBadge}
              onChange={(event) =>
                setPropertyForm((prev) => ({ ...prev, verifiedBadge: event.target.checked }))
              }
            />
            Verified Badge
          </label>
          <label className="flex items-center gap-2 text-sm text-zinc-700">
            <input
              type="checkbox"
              checked={propertyForm.newLaunch}
              onChange={(event) =>
                setPropertyForm((prev) => ({ ...prev, newLaunch: event.target.checked }))
              }
            />
            New Launch
          </label>

          <select
            value={propertyForm.recordStatus}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, recordStatus: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
          >
            {PROPERTY_RECORD_STATUSES.map((status) => (
              <option key={status} value={status}>
                {status}
              </option>
            ))}
          </select>
          <input
            required
            value={propertyForm.metaTitle}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, metaTitle: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm"
            placeholder="Meta Title"
          />
          <textarea
            required
            value={propertyForm.metaDescription}
            onChange={(event) =>
              setPropertyForm((prev) => ({ ...prev, metaDescription: event.target.value }))
            }
            className="rounded-lg border border-zinc-300 px-3 py-2 text-sm md:col-span-2"
            rows={2}
            placeholder="Meta Description"
          />

          <div className="flex gap-2 md:col-span-2">
            <button
              disabled={submittingProperty}
              className="rounded-lg bg-zinc-900 px-4 py-2 text-sm font-semibold text-white disabled:opacity-70"
            >
              {submittingProperty
                ? "Saving..."
                : editingId
                ? "Update Property"
                : "Create Property"}
            </button>
            {editingId ? (
              <button
                type="button"
                onClick={() => {
                  setEditingId(null);
                  setPropertyForm(initialPropertyForm);
                }}
                className="rounded-lg border border-zinc-300 px-4 py-2 text-sm font-semibold text-zinc-700"
              >
                Cancel Edit
              </button>
            ) : null}
          </div>
        </form>
      </div>

      <div className="rounded-2xl border border-zinc-200 bg-white p-5 shadow-sm">
        <h2 className="text-xl font-semibold text-zinc-900">Property Records</h2>
        <div className="mt-4 grid gap-3">
          {properties.map((property) => (
            <article key={property._id} className="rounded-xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
                {property.recordStatus}
              </p>
              <h3 className="mt-1 text-lg font-semibold text-zinc-900">{property.propertyTitle}</h3>
              <p className="mt-1 text-sm text-zinc-600">
                {property.propertyType} | {property.areaSector}, {property.city} | INR {property.price}
              </p>
              <div className="mt-3 flex gap-2">
                <button
                  onClick={() => startEdit(property)}
                  className="rounded-md border border-zinc-300 px-3 py-1 text-xs font-semibold text-zinc-700"
                >
                  Edit
                </button>
                {canDeleteProperty ? (
                  <button
                    onClick={() => deleteProperty(property._id)}
                    className="rounded-md bg-red-600 px-3 py-1 text-xs font-semibold text-white"
                  >
                    Delete
                  </button>
                ) : null}
              </div>
            </article>
          ))}
          {properties.length === 0 ? (
            <p className="rounded-lg border border-zinc-200 p-4 text-sm text-zinc-700">
              No properties found.
            </p>
          ) : null}
        </div>
      </div>
    </section>
  );
}
